from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentences = []

    for subject, triples_list in subject_map.items():
        # Handle special cases with natural language patterns
        if any(p == "runwayLength" for p, _ in triples_list):
            # For runwayLength, use "The runway length of X is Y" format
            runway_triple = next(t for t in triples_list if t.predicate == "runwayLength")
            sentence = f"The runway length of {subject} is {runway_triple.object} metres."
            sentences.append(sentence)
            continue

        if any(p == "leader" for p, _ in triples_list):
            # For leader, use "The leader of X is Y" format
            leader_triple = next(t for t in triples_list if t.predicate == "leader")
            sentence = f"The leader of {subject} is {leader_triple.object}."
            sentences.append(sentence)
            continue

        if any(p == "1stRunwayLengthFeet" for p, _ in triples_list):
            # For 1stRunwayLengthFeet, use "The length of the 1st runway at X is Y" format
            runway_triple = next(t for t in triples_list if t.predicate == "1stRunwayLengthFeet")
            sentence = f"The length of the 1st runway at {subject} is {runway_triple.object} feet."
            sentences.append(sentence)
            continue

        # Handle other common cases with natural phrasing
        base_sentence = subject
        clauses = []

        for predicate, obj in triples_list:
            if predicate == "cityServed":
                clauses.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                clauses.append(f"The mayor of {subject} is {obj}")
            elif predicate == "isPartOf":
                clauses.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                clauses.append(f"is operated by {obj}")
            elif predicate == "location":
                clauses.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                clauses.append(f"is located at an elevation of {obj} metres above sea level")
            elif predicate == "country":
                clauses.append(f"is located in {obj}")
            elif predicate == "capital":
                clauses.append(f"The capital of {subject} is {obj}")
            elif predicate == "language":
                # Remove " language" suffix for more natural phrasing
                obj_clean = obj.replace(" language", "") if " language" in obj else obj
                clauses.append(f"where {obj_clean} is spoken")
            elif predicate == "owner":
                clauses.append(f"is owned by {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                clauses.append(f"is located at an elevation of {obj} feet above sea level")
            elif predicate == "icaoLocationIdentifier":
                clauses.append(f"has the ICAO code {obj}")
            elif predicate == "locationIdentifier":
                clauses.append(f"has the location identifier {obj}")
            elif predicate == "iataLocationIdentifier":
                clauses.append(f"has the IATA code {obj}")
            elif predicate == "nativeName":
                clauses.append(f"is also known as {obj}")
            elif predicate == "leaderParty":
                clauses.append(f"has a leader party of {obj}")
            elif predicate == "1stRunwaySurfaceType":
                clauses.append(f"has a first runway with surface type {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                clauses.append(f"has a third runway that is {obj} feet long")
            elif predicate == "1stRunwayNumber":
                clauses.append(f"has a first runway numbered {obj}")
            elif predicate == "4thRunwayLengthFeet":
                clauses.append(f"has a fourth runway that is {obj} feet long")
            elif predicate == "4thRunwaySurfaceType":
                clauses.append(f"has a fourth runway made of {obj}")
            elif predicate == "5thRunwayNumber":
                clauses.append(f"has a fifth runway numbered {obj}")
            elif predicate == "5thRunwaySurfaceType":
                clauses.append(f"has a fifth runway with surface type {obj}")
            elif predicate == "countySeat":
                clauses.append(f"The county seat of {subject} is {obj}")
            elif predicate == "chief":
                clauses.append(f"The chief of {subject} is {obj}")
            elif predicate == "foundedBy":
                clauses.append(f"was founded by {obj}")
            elif predicate == "postalCode":
                clauses.append(f"has the postal code {obj}")
            else:
                clauses.append(f"has a {predicate} of {obj}")

        # Combine clauses into a single sentence
        if clauses:
            sentence = base_sentence + " " + ", ".join(clauses)
        else:
            sentence = base_sentence
        sentences.append(sentence + ".")

    # Join all sentences with " and " to create a complex sentence
    result = " and ".join(sentences)
    return result if result else "."

